import xml.etree.ElementTree as et
from collections import namedtuple
from os import PathLike  # noqa # pylint: disable=unused-import
from typing import List, Optional, Dict, Any, Iterable, Union, TextIO, BinaryIO

from typing_extensions import Self

from ..boundingboxes import BoundingBox, OrientedDetectionBox, DetectionBox, findtext

AnnotationSize = namedtuple("AnnotationSize", ["width", "height", "depth"])
FileLike = Union[str, bytes, "PathLike[Any]", int, TextIO, BinaryIO]


class PascalVocObject:
    """Python object for the 'object' part in the PascalVoc xml file."""

    def __init__(
        self,
        bounding_box: BoundingBox,
        name: str,
        *,
        pose: str = "Unspecified",
        truncated: int = 0,
        difficult: int = 0,
        score: Optional[float] = None,
        identifier: Optional[int] = None,
        **kwargs: Dict[str, Any],
    ) -> None:
        self.name = name
        self.pose = pose
        self.truncated = truncated
        self.difficult = difficult
        self.bounding_box = bounding_box.astype(int)
        self.score = score
        self.identifier = identifier
        self.__dict__.update(kwargs)

    def is_inside(self, box: BoundingBox) -> bool:
        return self.bounding_box in box

    def write_node(self, root: et.Element) -> None:
        obj = et.SubElement(root, "object")

        et.SubElement(obj, "name").text = self.name
        et.SubElement(obj, "pose").text = self.pose
        et.SubElement(obj, "truncated").text = str(self.truncated)
        et.SubElement(obj, "difficult").text = str(self.difficult)
        if self.score is not None:
            et.SubElement(obj, "score").text = str(self.score)
        if self.identifier is not None:
            et.SubElement(obj, "identifier").text = str(self.identifier)

        self.bounding_box.write_node(obj)

    def __eq__(self, other: object) -> bool:
        return self.__dict__ == other.__dict__

    @classmethod
    def from_xml_node(cls, xml_node: et.Element) -> Self:
        bbox: Optional[et.Element] = xml_node.find("bndbox")
        if bbox is None:
            raise AttributeError(
                f"No element with `bndbox` tag was found in XML node with '{xml_node.tag}'"
            )
        class_name: str = findtext(xml_node, "name")
        score: Optional[str] = xml_node.findtext("score")
        identifier: Optional[str] = xml_node.findtext("identifier")
        angle: Optional[str] = bbox.findtext("angle")
        if angle is not None:
            obb = OrientedDetectionBox.from_xml_node(bbox)
            obb.class_name = class_name
            if score is not None:
                obb.score = float(score)
            return cls.from_detection_box(obb)
        bb = BoundingBox.from_xml_node(bbox)
        return cls(
            bb,
            class_name,
            pose=findtext(xml_node, "pose"),
            truncated=int(findtext(xml_node, "truncated")),
            difficult=int(findtext(xml_node, "difficult")),
            score=float(score) if score is not None else None,
            identifier=int(identifier) if identifier is not None else None,
        )

    # TODO: to remove as it is the same as base constructor
    @classmethod
    def from_bounding_box(
        cls,
        bounding_box: BoundingBox,
        class_name: str,
        pose: str = "Unspecified",
        truncated: int = 0,
        difficult: int = 0,
        score: Optional[float] = None,
        identifier: Optional[int] = None,
    ) -> Self:
        return cls(
            bounding_box,
            class_name,
            pose=pose,
            truncated=truncated,
            difficult=difficult,
            score=score,
            identifier=identifier,
        )

    @classmethod
    def from_detection_box(cls, detection_box: DetectionBox) -> Self:
        return cls.from_bounding_box(
            detection_box, detection_box.class_name, score=detection_box.score
        )

    def to_detection_box(self) -> DetectionBox:
        if isinstance(self.bounding_box, DetectionBox):
            return self.bounding_box
        else:
            kwargs: Dict[str, Any] = {}
            if self.score is not None:
                kwargs["score"] = self.score
            detection_box = DetectionBox.from_bounding_box(
                self.bounding_box, class_name=self.name, **kwargs
            )
            return detection_box

    @classmethod
    def from_dict(cls, pascal_voc_object_dict: Dict[str, Any]) -> Self:
        """Create an instance from a dict.

        :param pascal_voc_object_dict: conventional dict containing the object in json format
        :return: PascalVocXml
        """
        copied: Dict[str, Any] = pascal_voc_object_dict.copy()
        return cls(
            BoundingBox(**copied.pop("bndbox")),
            **copied,
        )


class PascalVocXml:
    """Class that represent a PascalVOC challenge annotation file.
    Changes made to attributes of an instance won't be reflected in the xml file until the file is re-written
    """

    def __init__(
        self,
        objects: List[PascalVocObject],
        size: AnnotationSize,
        *,
        filename: str = "Unspecified",
        source_db: str = "Unspecified",
        folder: str = "Unspecified",
        path: str = "Unspecified",
        segmented: int = 0,
        file_path: Optional[str] = None,
    ) -> None:
        self.folder = folder
        self.filename = filename
        self.path = path
        self.source_db = source_db
        self.size = size
        self.segmented = segmented
        self.objects = objects
        self.file_path = file_path

    def crop(self, bbox: BoundingBox) -> None:
        """Crops the annotation by removing objects outside the
        specified bbox. Updates the member field AnnotationSize.

        :param bbox: BoundingBox instance representing the ROI.
        """
        self.remove_objects_outside(bbox)
        xmin, ymin = bbox.point_min

        for obj in self.objects:
            obj.bounding_box.subtract(xmin, ymin)

        self.size = AnnotationSize(bbox.width, bbox.height, self.size.depth)

    def remove_objects_outside(self, bbox: BoundingBox) -> None:
        """Removes all the annotated objects that are outside
        the bounding box.

        :param bbox: BoundingBox instance representing the ROI.
        """

        self.objects = [obj for obj in self.objects if obj.is_inside(bbox)]

    def get_xml_content(self) -> et.ElementTree:
        """
        Convert to XML element tree
        """
        root = et.Element("annotation")

        et.SubElement(root, "folder").text = self.folder
        et.SubElement(root, "filename").text = self.filename
        et.SubElement(root, "path").text = self.path

        source = et.SubElement(root, "source")
        et.SubElement(source, "database").text = self.source_db

        size = et.SubElement(root, "size")
        et.SubElement(size, "width").text = str(self.size.width)
        et.SubElement(size, "height").text = str(self.size.height)
        et.SubElement(size, "depth").text = str(self.size.depth)

        et.SubElement(root, "segmented").text = str(self.segmented)

        for obj in self.objects:
            obj.write_node(root)

        tree = et.ElementTree(root)
        return tree

    def write(self, file_name: Optional[str] = None) -> None:
        """Writes to a file in xml format.

        :param file_name: Path to write to, must be specified if it was not specified when creating the instance.
        """
        file_name = file_name if file_name is not None else self.file_path
        if file_name is None:
            raise ValueError(
                "You have to provide a filename to write the file to,"
                "as it was not specified when calling __init__"
            )

        tree = self.get_xml_content()
        tree.write(file_name)

    def __iter__(self) -> Iterable[PascalVocObject]:
        """Returns an iterator over the annotated objects"""
        return iter(self.objects)

    def __eq__(self, other: object) -> bool:
        return self.__dict__ == other.__dict__

    @classmethod
    def from_xml(cls, source: FileLike) -> Self:
        """Create an instance from a xml file.

        :param source: str or file-like object
        :return: PascalVocXml
        """
        tree = et.parse(source)
        root = tree.getroot()

        annotation = cls(
            [
                PascalVocObject.from_xml_node(obj_node)
                for obj_node in root.findall("object")
            ],
            AnnotationSize(
                int(findtext(root, "size/width")),
                int(findtext(root, "size/height")),
                int(findtext(root, "size/depth")),
            ),
            filename=findtext(root, "filename"),
            folder=findtext(root, "folder"),
            path=root.findtext("path", default=""),
            source_db=findtext(root, "source/database"),
            segmented=int(findtext(root, "segmented")),
            file_path=source if isinstance(source, str) else None,
        )

        return annotation

    @classmethod
    def from_dict(cls, annotation: Dict[str, Any]) -> Self:
        """Create an instance from a dict.

        :param annotation: conventional dict containing the object in json format
        :return: PascalVocXml
        """
        return cls(
            [PascalVocObject.from_dict(obj_json) for obj_json in annotation["objects"]],
            AnnotationSize(
                annotation["size"]["width"],
                annotation["size"]["height"],
                annotation["size"]["depth"],
            ),
            filename=annotation["filename"],
            folder=annotation["folder"],
            path=annotation["path"],
            source_db=annotation["source"]["database"],
            segmented=annotation["segmented"],
        )

    def __str__(self) -> str:
        return f"PascalVocXml(filename={self.filename}, size={self.size})"
